from math import gcd
def ok(n):
    digs = list(map(int, str(n)))
    return all(gcd(n, d) == 1 for d in digs) and gcd(n, sum(digs)) == 1
print([k for k in range(333) if ok(k)]) # _Michael S. Branicky_, Apr 08 2026

